window.BACTERIAL_QUESTIONS=window.BACTERIAL_QUESTIONS.concat([{"id":"Q051","topic":"erysipelas","topicEn":"Erysipelas","topicAr":"الحمرة","type":"Case","difficulty":"Medium","source":"PDF pp. 13, 15","question":{"en":"A patient has recurrent lower-leg erysipelas. Which modifiable background problem should be actively managed to reduce recurrence?","ar":"مريض يعاني نوبات متكررة من حمرة الساق. أي مشكلة خلفية قابلة للتعديل ينبغي علاجها لتقليل التكرار؟"},"options":[{"letter":"A","en":"Chronic edema or venous insufficiency","ar":"الوذمة المزمنة أو القصور الوريدي"},{"letter":"B","en":"Normal hair growth","ar":"نمو الشعر الطبيعي"},{"letter":"C","en":"Brown eye color","ar":"لون العين البني"},{"letter":"D","en":"High dietary fiber","ar":"تناول ألياف غذائية مرتفع"}],"correct":"A","explanation":{"en":"Chronic edema, lymphedema, venous insufficiency, obesity, and barrier disorders predispose to recurrence.","ar":"تُهيئ الوذمة المزمنة والوذمة اللمفية والقصور الوريدي والسمنة واضطرابات الحاجز للتكرار."},"reasoning":{"en":"Focus on persistent local fluid and barrier problems maintain susceptibility even after antibiotics. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تُبقي مشكلات السوائل والحاجز الموضعية القابلية للعدوى حتى بعد المضادات. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q052","topic":"erysipelas","topicEn":"Erysipelas","topicAr":"الحمرة","type":"Case","difficulty":"Medium","source":"PDF pp. 15-16","question":{"en":"A patient with erysipelas is hypotensive, febrile, and unable to tolerate oral medication. What is the best disposition?","ar":"مريض بالحمرة يعاني انخفاض الضغط والحمى ولا يستطيع تحمل الدواء الفموي. ما التصرف الأفضل؟"},"options":[{"letter":"A","en":"Hospital admission for parenteral therapy and assessment of sepsis","ar":"دخول المستشفى للعلاج الحقني وتقييم الإنتان"},{"letter":"B","en":"Routine topical antibiotic at home","ar":"مضاد موضعي روتيني بالمنزل"},{"letter":"C","en":"No treatment until culture results return","ar":"عدم العلاج حتى ظهور المزرعة"},{"letter":"D","en":"Elective review after one month","ar":"مراجعة اختيارية بعد شهر"}],"correct":"A","explanation":{"en":"Hypotension, systemic toxicity, and inability to take oral therapy are indications for admission and IV treatment.","ar":"انخفاض الضغط والسمية الجهازية وعدم القدرة على تناول العلاج الفموي مؤشرات لدخول المستشفى والعلاج الوريدي."},"reasoning":{"en":"Focus on physiologic instability overrides outpatient treatment options. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يتغلب عدم الاستقرار الفسيولوجي على خيارات العلاج الخارجي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q053","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"MCQ","difficulty":"Easy","source":"PDF p. 14","question":{"en":"Which tissues are involved in cellulitis?","ar":"ما الأنسجة التي يشملها التهاب النسيج الخلوي؟"},"options":[{"letter":"A","en":"Dermis and subcutaneous fat","ar":"الأدمة والدهون تحت الجلد"},{"letter":"B","en":"Epidermis only","ar":"البشرة فقط"},{"letter":"C","en":"Hair shaft only","ar":"ساق الشعرة فقط"},{"letter":"D","en":"Bone cortex only","ar":"قشرة العظم فقط"}],"correct":"A","explanation":{"en":"Cellulitis is a deeper infection of the dermis and subcutaneous tissue.","ar":"التهاب النسيج الخلوي عدوى أعمق تشمل الأدمة والأنسجة تحت الجلد."},"reasoning":{"en":"Focus on deep tissue involvement explains diffuse swelling and poorly defined margins. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تفسر إصابة الأنسجة العميقة التورم المنتشر والحدود غير الواضحة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q054","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"MCQ","difficulty":"Easy","source":"PDF p. 14","question":{"en":"What margin is characteristic of cellulitis?","ar":"ما نوع الحدود المميزة لالتهاب النسيج الخلوي؟"},"options":[{"letter":"A","en":"Ill-defined diffuse margins","ar":"حدود منتشرة غير واضحة"},{"letter":"B","en":"Sharply raised margins","ar":"حدود مرتفعة حادة"},{"letter":"C","en":"A circular vesicular rim only","ar":"طوق حويصلي دائري فقط"},{"letter":"D","en":"A black eschar border","ar":"حد قشرة سوداء"}],"correct":"A","explanation":{"en":"Cellulitis typically presents with diffuse erythema, warmth, swelling, and poorly defined borders.","ar":"يظهر التهاب النسيج الخلوي عادةً باحمرار ودفء وتورم منتشر مع حدود غير واضحة."},"reasoning":{"en":"Focus on poor definition reflects deeper spread through tissue planes. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تعكس الحدود غير الواضحة الانتشار الأعمق عبر مستويات الأنسجة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q055","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"MCQ","difficulty":"Easy","source":"PDF pp. 14-15","question":{"en":"Which organisms are the most common causes of ordinary cellulitis?","ar":"ما الكائنات الأكثر شيوعًا في التهاب النسيج الخلوي المعتاد؟"},"options":[{"letter":"A","en":"Streptococcus pyogenes and Staphylococcus aureus","ar":"العقدية المقيحة والمكورات العنقودية الذهبية"},{"letter":"B","en":"Bartonella henselae and Bacillus anthracis","ar":"بارتونيلا هينسيلا والعصوية الجمرية"},{"letter":"C","en":"Candida albicans and dermatophytes","ar":"المبيضة البيضاء والفطريات الجلدية"},{"letter":"D","en":"Clostridioides difficile and Helicobacter pylori","ar":"المطثية العسيرة والملوية البوابية"}],"correct":"A","explanation":{"en":"Streptococci and S. aureus, including MRSA in selected settings, are the major pathogens.","ar":"العقديات والمكورات العنقودية الذهبية، بما فيها MRSA في حالات مختارة، هي الممرضات الرئيسية."},"reasoning":{"en":"Focus on empiric therapy is built around these likely gram-positive organisms. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يُبنى العلاج التجريبي حول هذه الجراثيم إيجابية الغرام المحتملة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q056","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"MCQ","difficulty":"Easy","source":"PDF p. 14","question":{"en":"Which body region is most commonly affected by cellulitis?","ar":"أي منطقة من الجسم تُصاب غالبًا بالتهاب النسيج الخلوي؟"},"options":[{"letter":"A","en":"Lower extremities","ar":"الأطراف السفلية"},{"letter":"B","en":"Tongue only","ar":"اللسان فقط"},{"letter":"C","en":"Fingernails only","ar":"الأظافر فقط"},{"letter":"D","en":"External ear canal only","ar":"قناة الأذن الخارجية فقط"}],"correct":"A","explanation":{"en":"The lower limbs are the most frequent site, although cellulitis may occur anywhere.","ar":"الأطراف السفلية هي الموضع الأكثر شيوعًا، رغم إمكانية حدوثه في أي مكان."},"reasoning":{"en":"Focus on lower-limb edema, tinea pedis, wounds, and venous disease commonly provide entry and susceptibility. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على توفر وذمة الساق وسعفة القدم والجروح والمرض الوريدي منافذ وعوامل قابلية شائعة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q057","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"MCQ","difficulty":"Medium","source":"PDF p. 14","question":{"en":"Which is a recognized complication of untreated cellulitis?","ar":"أي مما يلي مضاعفة معروفة لالتهاب النسيج الخلوي غير المعالج؟"},"options":[{"letter":"A","en":"Bacteremia or necrotizing fasciitis","ar":"تجرثم الدم أو التهاب اللفافة النخري"},{"letter":"B","en":"Cataract formation","ar":"تكون الساد"},{"letter":"C","en":"Peptic ulcer disease","ar":"القرحة الهضمية"},{"letter":"D","en":"Hyperthyroidism","ar":"فرط نشاط الدرقية"}],"correct":"A","explanation":{"en":"Cellulitis may progress to abscess, bacteremia, sepsis, or necrotizing soft-tissue infection.","ar":"قد يتطور التهاب النسيج الخلوي إلى خراج أو تجرثم الدم أو الإنتان أو عدوى الأنسجة الرخوة النخرية."},"reasoning":{"en":"Focus on deep spreading infection can escape local control and become systemic or necrotizing. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على قد تفلت العدوى العميقة المنتشرة من السيطرة الموضعية فتصبح جهازية أو نخرية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q058","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Case","difficulty":"Medium","source":"PDF pp. 15, 18-19","question":{"en":"A patient with cellulitis has fever above 38°C, sustained tachycardia, and hypotension. What does this imply?","ar":"مريض بالتهاب النسيج الخلوي لديه حمى أعلى من 38° وتسرع قلب مستمر وانخفاض ضغط. ماذا يعني ذلك؟"},"options":[{"letter":"A","en":"Systemic toxicity requiring parenteral assessment and likely admission","ar":"سمية جهازية تستلزم تقييمًا حقنيًا وغالبًا الدخول للمستشفى"},{"letter":"B","en":"Mild disease suitable for topical therapy only","ar":"مرض خفيف مناسب للعلاج الموضعي فقط"},{"letter":"C","en":"A definite fungal infection","ar":"عدوى فطرية مؤكدة"},{"letter":"D","en":"No need for urgent reassessment","ar":"لا حاجة لإعادة تقييم عاجلة"}],"correct":"A","explanation":{"en":"Fever, sustained tachycardia, and hypotension are systemic toxicity signs and indications for escalated care.","ar":"الحمى وتسرع القلب المستمر وانخفاض الضغط علامات سمية جهازية ومؤشرات لتصعيد الرعاية."},"reasoning":{"en":"Focus on vital-sign instability is more important than lesion size alone. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على عدم استقرار العلامات الحيوية أهم من حجم الآفة وحده. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q059","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Case","difficulty":"Medium","source":"PDF p. 15","question":{"en":"The area of erythema doubles in size within 24 hours. What is the appropriate interpretation?","ar":"تضاعفت مساحة الاحمرار خلال 24 ساعة. ما التفسير المناسب؟"},"options":[{"letter":"A","en":"Rapid progression is an admission/parenteral-therapy warning sign","ar":"التقدم السريع علامة تحذير للدخول والعلاج الحقني"},{"letter":"B","en":"This proves spontaneous resolution","ar":"يثبت ذلك الشفاء التلقائي"},{"letter":"C","en":"It excludes bacterial disease","ar":"يستبعد المرض البكتيري"},{"letter":"D","en":"It is typical of stable mild cellulitis","ar":"أمر نموذجي لالتهاب خلوي خفيف مستقر"}],"correct":"A","explanation":{"en":"Rapidly expanding erythema suggests aggressive infection and is a criterion for parenteral therapy or hospitalization.","ar":"يشير توسع الاحمرار بسرعة إلى عدوى عدوانية ويُعد معيارًا للعلاج الحقني أو الدخول للمستشفى."},"reasoning":{"en":"Focus on rate of spread is a severity marker independent of the initial area. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على سرعة الانتشار مؤشر شدة مستقل عن المساحة الأولية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q060","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Case","difficulty":"Medium","source":"PDF pp. 15, 19","question":{"en":"A patient with mild-looking cellulitis is vomiting repeatedly and cannot absorb oral medication. What is the best next step?","ar":"مريض يبدو التهاب النسيج الخلوي لديه خفيفًا لكنه يتقيأ باستمرار ولا يستطيع امتصاص الدواء الفموي. ما الخطوة التالية الأفضل؟"},"options":[{"letter":"A","en":"Use parenteral therapy and assess need for admission","ar":"استخدام العلاج الحقني وتقييم الحاجة للدخول"},{"letter":"B","en":"Give a lower oral dose","ar":"إعطاء جرعة فموية أقل"},{"letter":"C","en":"Stop antibacterial treatment","ar":"إيقاف العلاج المضاد للبكتيريا"},{"letter":"D","en":"Use topical antifungal therapy","ar":"استخدام مضاد فطري موضعي"}],"correct":"A","explanation":{"en":"Inability to tolerate or absorb oral antibiotics is itself an indication for parenteral treatment.","ar":"عدم القدرة على تحمل أو امتصاص المضادات الفموية هو في حد ذاته مؤشر للعلاج الحقني."},"reasoning":{"en":"Focus on an effective route is essential even when the visible lesion is not extensive. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على ضرورة طريق إعطاء فعال قائمة حتى لو لم تكن الآفة واسعة ظاهريًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q061","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Case","difficulty":"Medium","source":"PDF p. 15","question":{"en":"An immunocompromised patient has cellulitis but only a low-grade fever. How should the low fever influence disposition?","ar":"مريض مثبط المناعة لديه التهاب نسيج خلوي مع حمى بسيطة فقط. كيف تؤثر الحمى البسيطة على قرار العلاج؟"},"options":[{"letter":"A","en":"Immunocompromise may still justify admission despite modest fever","ar":"قد يبرر تثبيط المناعة الدخول رغم تواضع الحمى"},{"letter":"B","en":"Low fever always proves mild disease","ar":"الحمى البسيطة تثبت دائمًا أن المرض خفيف"},{"letter":"C","en":"Immunocompromise reduces risk","ar":"تثبيط المناعة يقلل الخطر"},{"letter":"D","en":"Only lesion color matters","ar":"لون الآفة فقط هو المهم"}],"correct":"A","explanation":{"en":"Immunocompromised patients may deteriorate without dramatic inflammatory signs and are listed among patients needing parenteral assessment.","ar":"قد يتدهور المرضى مثبطو المناعة دون علامات التهابية شديدة، وهم ضمن الفئات التي تحتاج تقييمًا للعلاج الحقني."},"reasoning":{"en":"Focus on host risk can outweigh the apparent intensity of fever. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على قد تتغلب خطورة المضيف على شدة الحمى الظاهرة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q062","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Case","difficulty":"Medium","source":"PDF pp. 16-17","question":{"en":"A patient has rapidly progressive leg erythema with severe pain far greater than the visible findings. What must be urgently excluded?","ar":"مريض لديه احمرار سريع التقدم بالساق مع ألم شديد يفوق كثيرًا الموجود بالفحص. ما الحالة التي يجب استبعادها عاجلًا؟"},"options":[{"letter":"A","en":"Necrotizing fasciitis","ar":"التهاب اللفافة النخري"},{"letter":"B","en":"Localized erythrasma","ar":"إريثرازما موضعية"},{"letter":"C","en":"Simple non-bullous impetigo","ar":"قوباء غير فقاعية بسيطة"},{"letter":"D","en":"Uncomplicated folliculitis","ar":"التهاب جريبات بسيط"}],"correct":"A","explanation":{"en":"Pain out of proportion is a major red flag for deep ischemia or necrotizing infection and requires immediate surgical assessment.","ar":"الألم غير المتناسب علامة خطر كبيرة لإقفار عميق أو عدوى نخرية ويستلزم تقييمًا جراحيًا فوريًا."},"reasoning":{"en":"Focus on the mismatch between pain and surface appearance is the key emergency clue. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على عدم التناسب بين الألم والمظهر السطحي هو دليل الطوارئ الأساسي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q063","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Case","difficulty":"Medium","source":"PDF pp. 16-18","question":{"en":"Which clinical situation requires immediate hospitalization and possible urgent surgery rather than routine cellulitis treatment?","ar":"أي حالة سريرية تستلزم دخولًا فوريًا واحتمال جراحة عاجلة بدل علاج التهاب النسيج الخلوي الروتيني؟"},"options":[{"letter":"A","en":"Suspected necrotizing soft-tissue infection","ar":"اشتباه عدوى نخرية بالأنسجة الرخوة"},{"letter":"B","en":"Stable localized erythema without systemic signs","ar":"احمرار موضعي مستقر دون علامات جهازية"},{"letter":"C","en":"Mild itching after shaving","ar":"حكة خفيفة بعد الحلاقة"},{"letter":"D","en":"Chronic asymptomatic flexural scaling","ar":"قشور مزمنة دون أعراض في الثنيات"}],"correct":"A","explanation":{"en":"Necrotizing infection is a surgical emergency requiring immediate broad antimicrobial therapy and debridement.","ar":"العدوى النخرية طارئ جراحي يحتاج مضادات واسعة فورية وتنضيرًا جراحيًا."},"reasoning":{"en":"Focus on routine oral pathways are unsafe when tissue necrosis is suspected. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تكون مسارات العلاج الفموي الروتيني غير آمنة عند الاشتباه في نخر الأنسجة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q064","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Treatment","difficulty":"Hard","source":"PDF p. 19","question":{"en":"What empiric regimen is suggested for cellulitis with severe sepsis?","ar":"ما النظام التجريبي المقترح لالتهاب النسيج الخلوي المصحوب بإنتان شديد؟"},"options":[{"letter":"A","en":"Vancomycin or daptomycin plus cefepime or meropenem","ar":"فانكوميسين أو دابتومايسين مع سيفيبيم أو ميروبينيم"},{"letter":"B","en":"Topical mupirocin alone","ar":"ميوبيروسين موضعي وحده"},{"letter":"C","en":"Penicillin V alone","ar":"بنسلين V وحده"},{"letter":"D","en":"Oral erythromycin only","ar":"إريثرومايسين فموي فقط"}],"correct":"A","explanation":{"en":"Severe sepsis requires broad IV coverage including MRSA and gram-negative pathogens, using an anti-MRSA agent plus cefepime or meropenem.","ar":"يحتاج الإنتان الشديد تغطية وريدية واسعة تشمل MRSA وسالبات الغرام باستخدام دواء ضد MRSA مع سيفيبيم أو ميروبينيم."},"reasoning":{"en":"Focus on hemodynamic severity requires broad immediate coverage before narrowing. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تتطلب الشدة الديناميكية الدموية تغطية واسعة فورية قبل التضييق. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q065","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Treatment","difficulty":"Medium","source":"PDF pp. 19-20","question":{"en":"A patient needs IV therapy but has no MRSA indication. Which option is appropriate?","ar":"مريض يحتاج علاجًا وريديًا لكن لا توجد لديه دلالة لتغطية MRSA. أي خيار مناسب؟"},"options":[{"letter":"A","en":"Cefazolin","ar":"سيفازولين"},{"letter":"B","en":"Doxycycline alone","ar":"دوكسيسيكلين وحده"},{"letter":"C","en":"Fluconazole","ar":"فلوكونازول"},{"letter":"D","en":"Acyclovir","ar":"أسيكلوفير"}],"correct":"A","explanation":{"en":"Cefazolin, flucloxacillin, nafcillin, or oxacillin are appropriate IV options for streptococci and MSSA when MRSA coverage is unnecessary.","ar":"يُعد السيفازولين أو الفلوكلوكساسيلين أو النافسيلين أو الأوكساسيلين خيارات وريدية مناسبة للعقديات وMSSA عند عدم الحاجة لتغطية MRSA."},"reasoning":{"en":"Focus on the regimen should cover streptococci and MSSA without unnecessary MRSA breadth. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على ينبغي أن يغطي النظام العقديات وMSSA دون اتساع غير ضروري لـMRSA. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q066","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Treatment","difficulty":"Medium","source":"PDF pp. 18-20","question":{"en":"A patient requires IV therapy and has purulent drainage plus prior MRSA infection. Which agent is appropriate?","ar":"مريض يحتاج علاجًا وريديًا ولديه إفراز قيحي وسابقة MRSA. أي دواء مناسب؟"},"options":[{"letter":"A","en":"Vancomycin","ar":"فانكوميسين"},{"letter":"B","en":"Amoxicillin alone","ar":"أموكسيسيلين وحده"},{"letter":"C","en":"Penicillin V alone","ar":"بنسلين V وحده"},{"letter":"D","en":"Topical fusidic acid alone","ar":"حمض الفيوسيديك موضعي وحده"}],"correct":"A","explanation":{"en":"Vancomycin or daptomycin is appropriate when parenteral MRSA coverage is indicated.","ar":"يُعد الفانكوميسين أو الدابتومايسين مناسبًا عند الحاجة لتغطية MRSA بالحقن."},"reasoning":{"en":"Focus on purulence and prior MRSA strongly raise the probability of resistant staphylococci. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على ترفع القيحية وسابقة MRSA احتمال العنقوديات المقاومة بدرجة كبيرة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q067","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Treatment","difficulty":"Easy","source":"PDF p. 19","question":{"en":"Which oral agent is a common first-line choice for uncomplicated nonpurulent cellulitis?","ar":"أي دواء فموي يُعد خيار خط أول شائعًا لالتهاب النسيج الخلوي غير القيحي البسيط؟"},"options":[{"letter":"A","en":"Cephalexin","ar":"سيفاليكسين"},{"letter":"B","en":"Linezolid for every patient","ar":"لينيزوليد لكل مريض"},{"letter":"C","en":"Meropenem orally","ar":"ميروبينيم فموي"},{"letter":"D","en":"Amphotericin B","ar":"أمفوتيريسين B"}],"correct":"A","explanation":{"en":"Cephalexin is commonly used because it covers streptococci and MSSA in uncomplicated skin infection.","ar":"يُستخدم السيفاليكسين شائعًا لأنه يغطي العقديات وMSSA في العدوى الجلدية البسيطة."},"reasoning":{"en":"Focus on nonpurulent uncomplicated disease usually does not require broad MRSA therapy. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على لا تحتاج العدوى البسيطة غير القيحية عادةً إلى علاج واسع ضد MRSA. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q068","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Treatment","difficulty":"Hard","source":"PDF pp. 19-20","question":{"en":"Which oral strategy is reasonable when MRSA coverage is needed but reliable streptococcal coverage must also be maintained?","ar":"أي استراتيجية فموية مناسبة عند الحاجة لتغطية MRSA مع الحفاظ على تغطية موثوقة للعقديات؟"},"options":[{"letter":"A","en":"Amoxicillin plus doxycycline","ar":"أموكسيسيلين مع دوكسيسيكلين"},{"letter":"B","en":"Doxycycline alone in all cases","ar":"دوكسيسيكلين وحده في كل الحالات"},{"letter":"C","en":"Penicillin V plus fluconazole","ar":"بنسلين V مع فلوكونازول"},{"letter":"D","en":"Ciprofloxacin alone","ar":"سيبروفلوكساسين وحده"}],"correct":"A","explanation":{"en":"Doxycycline covers MRSA but is not reliably active against group A streptococci, so pairing it with a beta-lactam can provide both targets.","ar":"يغطي الدوكسيسيكلين MRSA لكنه غير موثوق ضد العقديات من المجموعة A، لذا يمكن جمعه مع بيتا لاكتام لتغطية الهدفين."},"reasoning":{"en":"Focus on the combination compensates for the streptococcal gap of doxycycline. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يعوض الجمع نقص التغطية العقدية للدوكسيسيكلين. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q069","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"MCQ","difficulty":"Hard","source":"PDF p. 20","question":{"en":"Why should doxycycline alone be used cautiously for nonpurulent cellulitis?","ar":"لماذا ينبغي الحذر من استخدام الدوكسيسيكلين وحده في التهاب النسيج الخلوي غير القيحي؟"},"options":[{"letter":"A","en":"It is not reliably active against group A streptococci","ar":"ليس موثوق الفعالية ضد عقديات المجموعة A"},{"letter":"B","en":"It has no activity against MRSA","ar":"لا فعالية له ضد MRSA"},{"letter":"C","en":"It cannot be absorbed orally","ar":"لا يُمتص فمويًا"},{"letter":"D","en":"It only treats viruses","ar":"يعالج الفيروسات فقط"}],"correct":"A","explanation":{"en":"Doxycycline is useful for MRSA but does not provide dependable group A streptococcal coverage.","ar":"الدوكسيسيكلين مفيد ضد MRSA لكنه لا يوفر تغطية موثوقة لعقديات المجموعة A."},"reasoning":{"en":"Focus on nonpurulent cellulitis is often streptococcal, so a coverage gap matters clinically. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على غالبًا ما يكون التهاب النسيج الخلوي غير القيحي عقديًا، لذا يكون نقص التغطية مهمًا سريريًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q070","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Treatment","difficulty":"Medium","source":"PDF p. 19","question":{"en":"Which dose is listed for amoxicillin in mild nonpurulent cellulitis or erysipelas?","ar":"ما الجرعة المذكورة للأموكسيسيلين في التهاب النسيج الخلوي أو الحمرة الخفيفة غير القيحية؟"},"options":[{"letter":"A","en":"875 mg every 12 hours","ar":"875 مجم كل 12 ساعة"},{"letter":"B","en":"50 mg once weekly","ar":"50 مجم مرة أسبوعيًا"},{"letter":"C","en":"2 g every 2 hours","ar":"2 جم كل ساعتين"},{"letter":"D","en":"5 mg every 24 hours","ar":"5 مجم كل 24 ساعة"}],"correct":"A","explanation":{"en":"The chapter lists amoxicillin 875 mg every 12 hours as an oral option for mild nonpurulent cellulitis or erysipelas.","ar":"يذكر الفصل الأموكسيسيلين 875 مجم كل 12 ساعة كخيار فموي للحالات الخفيفة غير القيحية."},"reasoning":{"en":"Focus on the dosing question tests direct application of the treatment table. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يختبر سؤال الجرعة التطبيق المباشر لجدول العلاج. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q071","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Case","difficulty":"Hard","source":"PDF p. 19","question":{"en":"A patient with a severe immediate beta-lactam allergy requires IV treatment for cellulitis. Which option is most appropriate?","ar":"مريض لديه حساسية فورية شديدة من البيتا لاكتام ويحتاج علاجًا وريديًا لالتهاب النسيج الخلوي. أي خيار أنسب؟"},"options":[{"letter":"A","en":"Vancomycin","ar":"فانكوميسين"},{"letter":"B","en":"Cefazolin despite anaphylaxis without assessment","ar":"سيفازولين رغم التأق دون تقييم"},{"letter":"C","en":"Amoxicillin","ar":"أموكسيسيلين"},{"letter":"D","en":"Dicloxacillin","ar":"ديكلوكساسيلين"}],"correct":"A","explanation":{"en":"Vancomycin is the listed alternative when parenteral therapy is needed and a serious beta-lactam allergy precludes usual agents.","ar":"الفانكوميسين هو البديل المذكور عند الحاجة للعلاج الحقني ووجود حساسية خطيرة تمنع البيتا لاكتام المعتاد."},"reasoning":{"en":"Focus on the allergy removes standard anti-streptococcal and anti-MSSA beta-lactams from immediate use. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تستبعد الحساسية البيتا لاكتام المعتاد ضد العقديات وMSSA من الاستخدام الفوري. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q072","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"MCQ","difficulty":"Medium","source":"PDF p. 18","question":{"en":"Which factor is an indication for empiric MRSA coverage?","ar":"أي عامل يُعد دلالة للتغطية التجريبية لـMRSA؟"},"options":[{"letter":"A","en":"Known prior MRSA infection","ar":"إصابة سابقة معروفة بـMRSA"},{"letter":"B","en":"Stable chronic edema alone without infection","ar":"وذمة مزمنة مستقرة وحدها دون عدوى"},{"letter":"C","en":"Absence of purulence and toxicity","ar":"غياب القيح والسمية"},{"letter":"D","en":"A first mild episode with no risk factors","ar":"نوبة أولى خفيفة دون عوامل خطورة"}],"correct":"A","explanation":{"en":"Prior MRSA infection or colonization, purulent drainage, injection drug use, high-risk neutropenia, and systemic toxicity support empiric MRSA coverage.","ar":"تدعم سابقة الإصابة أو الاستعمار بـMRSA والإفراز القيحي وتعاطي الحقن وقلة العدلات عالية الخطورة والسمية الجهازية التغطية التجريبية."},"reasoning":{"en":"Focus on a documented prior resistant organism changes the pretest probability. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تغير سابقة الميكروب المقاوم الموثقة الاحتمال القبلي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q073","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Treatment","difficulty":"Hard","source":"PDF p. 18","question":{"en":"A culture later identifies a susceptible streptococcus in a clinically improving patient initially on broad therapy. What should be done?","ar":"أظهرت المزرعة لاحقًا عقدية حساسة لدى مريض يتحسن وكان يتلقى علاجًا واسعًا. ماذا ينبغي فعله؟"},"options":[{"letter":"A","en":"Narrow therapy to the confirmed pathogen","ar":"تضييق العلاج ليستهدف الممرض المؤكد"},{"letter":"B","en":"Add more broad-spectrum agents","ar":"إضافة أدوية أوسع"},{"letter":"C","en":"Continue all agents indefinitely","ar":"استمرار كل الأدوية بلا مدة محددة"},{"letter":"D","en":"Switch to antifungal therapy","ar":"التحول إلى مضاد فطري"}],"correct":"A","explanation":{"en":"Once a pathogen and susceptibility are known, therapy should be de-escalated to a targeted regimen.","ar":"عند معرفة الممرض وحساسيته ينبغي خفض العلاج إلى نظام موجه."},"reasoning":{"en":"Focus on de-escalation preserves efficacy while reducing toxicity and resistance pressure. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يحافظ تضييق العلاج على الفعالية مع تقليل السمية وضغط المقاومة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q074","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Case","difficulty":"Hard","source":"PDF pp. 16-17","question":{"en":"A patient has unilateral leg swelling, pain, and erythema but little warmth and no clear skin entry point. Which dangerous alternative diagnosis should remain in the differential?","ar":"مريض لديه تورم وألم واحمرار أحادي بالساق مع دفء قليل ودون منفذ جلدي واضح. أي تشخيص خطير بديل يجب أن يبقى في الاحتمالات؟"},"options":[{"letter":"A","en":"Deep vein thrombosis","ar":"الخثار الوريدي العميق"},{"letter":"B","en":"Localized impetigo","ar":"قوباء موضعية"},{"letter":"C","en":"Erythrasma","ar":"إريثرازما"},{"letter":"D","en":"Pediculosis","ar":"قمل"}],"correct":"A","explanation":{"en":"DVT can mimic cellulitis with unilateral swelling, pain, and erythema and carries a risk of pulmonary embolism.","ar":"قد يحاكي الخثار الوريدي العميق التهاب النسيج الخلوي بتورم وألم واحمرار أحادي ويحمل خطر الانصمام الرئوي."},"reasoning":{"en":"Focus on absence of a clear infectious portal and disproportionate swelling warrants vascular evaluation. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يستدعي غياب منفذ عدوى واضح والتورم البارز تقييمًا وعائيًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q075","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Image","difficulty":"Medium","source":"PDF p. 14","question":{"en":"The image shows diffuse lower-leg erythema and swelling with poorly defined margins. What is the most likely diagnosis?","ar":"تُظهر الصورة احمرارًا وتورمًا منتشرًا بأسفل الساق مع حدود غير واضحة. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Cellulitis","ar":"التهاب النسيج الخلوي"},{"letter":"B","en":"Erysipelas","ar":"الحمرة"},{"letter":"C","en":"Ecthyma","ar":"الإكثيما"},{"letter":"D","en":"Folliculitis","ar":"التهاب الجريبات"}],"correct":"A","explanation":{"en":"Diffuse warmth, edema, and ill-defined erythema are typical of cellulitis.","ar":"الدفء والتورم والاحمرار المنتشر غير المحدد علامات نموذجية لالتهاب النسيج الخلوي."},"reasoning":{"en":"Focus on the poorly demarcated deep inflammatory pattern distinguishes it from erysipelas. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يميز النمط الالتهابي العميق غير المحدد الحالة عن الحمرة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q076","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Image","difficulty":"Hard","source":"PDF pp. 16-18","question":{"en":"The image shows extensive tissue necrosis in a patient initially labeled as cellulitis. What is the required next action?","ar":"تُظهر الصورة نخرًا واسعًا بالأنسجة لدى مريض شُخّص أولًا بالتهاب نسيج خلوي. ما الإجراء المطلوب؟"},"options":[{"letter":"A","en":"Urgent surgical evaluation and debridement with broad IV antibiotics","ar":"تقييم جراحي عاجل وتنضير مع مضادات وريدية واسعة"},{"letter":"B","en":"Topical mupirocin and discharge","ar":"ميوبيروسين موضعي وخروج"},{"letter":"C","en":"Wait 72 hours for spontaneous improvement","ar":"الانتظار 72 ساعة للتحسن التلقائي"},{"letter":"D","en":"Treat with oral antihistamine only","ar":"العلاج بمضاد هيستامين فموي فقط"}],"correct":"A","explanation":{"en":"Visible necrosis suggests necrotizing soft-tissue infection, which requires immediate surgery and broad antimicrobial therapy.","ar":"يشير النخر الظاهر إلى عدوى نخرية بالأنسجة الرخوة تحتاج جراحة فورية ومضادات واسعة."},"reasoning":{"en":"Focus on necrosis converts a medical skin infection pathway into a surgical emergency. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يحول النخر مسار العدوى الجلدية الطبية إلى طارئ جراحي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q077","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Case","difficulty":"Hard","source":"PDF p. 18","question":{"en":"Cellulitis involves the hand after a deep puncture wound. Why should routine uncomplicated cellulitis pathways not be followed automatically?","ar":"حدث التهاب نسيج خلوي باليد بعد جرح وخزي عميق. لماذا لا ينبغي اتباع مسار التهاب النسيج الخلوي البسيط تلقائيًا؟"},"options":[{"letter":"A","en":"Hand involvement and deep wounds may require specialized evaluation and different coverage","ar":"إصابة اليد والجروح العميقة قد تحتاج تقييمًا متخصصًا وتغطية مختلفة"},{"letter":"B","en":"Hand infections are never bacterial","ar":"عدوى اليد ليست بكتيرية مطلقًا"},{"letter":"C","en":"All hand redness is erythrasma","ar":"كل احمرار باليد إريثرازما"},{"letter":"D","en":"Antibiotics are contraindicated in hand infections","ar":"المضادات ممنوعة في عدوى اليد"}],"correct":"A","explanation":{"en":"Face, neck, hand, perineum, deep wounds, and environmental exposures are red-flag contexts managed by site-specific guidance.","ar":"الوجه والرقبة واليد والعجان والجروح العميقة والتعرضات البيئية سياقات إنذار تُدار وفق إرشادات خاصة بالموقع."},"reasoning":{"en":"Focus on anatomical location can threaten function and involve deeper structures. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على قد يهدد الموقع التشريحي الوظيفة ويشمل تراكيب أعمق. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q078","topic":"cellulitis","topicEn":"Cellulitis","topicAr":"التهاب النسيج الخلوي","type":"Treatment","difficulty":"Hard","source":"PDF p. 20","question":{"en":"How should vancomycin exposure be monitored in serious MRSA cellulitis according to the chapter table?","ar":"كيف ينبغي مراقبة التعرض للفانكوميسين في التهاب نسيج خلوي خطير بسبب MRSA وفق جدول الفصل؟"},"options":[{"letter":"A","en":"Prefer AUC-guided monitoring, with trough monitoring as an alternative context","ar":"تُفضل المراقبة الموجهة بالـAUC مع استخدام الحضيض حسب السياق"},{"letter":"B","en":"No monitoring is ever required","ar":"لا يلزم أي رصد مطلقًا"},{"letter":"C","en":"Monitor only serum sodium","ar":"مراقبة صوديوم الدم فقط"},{"letter":"D","en":"Use a fixed dose regardless of weight or renal function","ar":"استخدام جرعة ثابتة بصرف النظر عن الوزن أو الكلى"}],"correct":"A","explanation":{"en":"The table notes weight-based dosing and monitoring by AUC or trough, with renal function and loading needs considered in severe infection.","ar":"يذكر الجدول الجرعات المعتمدة على الوزن والمراقبة بالـAUC أو الحضيض مع مراعاة وظائف الكلى وجرعة التحميل في العدوى الشديدة."},"reasoning":{"en":"Focus on vancomycin has variable pharmacokinetics and nephrotoxicity risk, so exposure should be individualized. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على للفانكوميسين حرائك دوائية متغيرة وخطر سمية كلوية، لذا يجب تخصيص التعرض. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q079","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"MCQ","difficulty":"Easy","source":"PDF p. 21","question":{"en":"What structure is primarily infected in bacterial folliculitis?","ar":"ما البنية المصابة أساسًا في التهاب الجريبات البكتيري؟"},"options":[{"letter":"A","en":"One or more hair follicles","ar":"جريب شعري واحد أو أكثر"},{"letter":"B","en":"The deep fascia","ar":"اللفافة العميقة"},{"letter":"C","en":"The periosteum","ar":"السمحاق"},{"letter":"D","en":"The lymph node capsule","ar":"محفظة العقدة اللمفية"}],"correct":"A","explanation":{"en":"Bacterial folliculitis is inflammation and infection centered on hair follicles.","ar":"التهاب الجريبات البكتيري هو التهاب وعدوى تتمركز حول جريبات الشعر."},"reasoning":{"en":"Focus on follicular centering is the defining anatomical feature. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على التمركز حول الجريب هو السمة التشريحية المحددة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q080","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"MCQ","difficulty":"Easy","source":"PDF p. 21","question":{"en":"Which organism most commonly causes ordinary bacterial folliculitis?","ar":"ما الكائن الأكثر شيوعًا في التهاب الجريبات البكتيري المعتاد؟"},"options":[{"letter":"A","en":"Staphylococcus aureus","ar":"المكورات العنقودية الذهبية"},{"letter":"B","en":"Bacillus anthracis","ar":"العصوية الجمرية"},{"letter":"C","en":"Bartonella henselae","ar":"بارتونيلا هينسيلا"},{"letter":"D","en":"Corynebacterium minutissimum","ar":"الوتدية الدقيقة"}],"correct":"A","explanation":{"en":"S. aureus is the most common cause of typical bacterial folliculitis.","ar":"تُعد المكورات العنقودية الذهبية السبب الأكثر شيوعًا لالتهاب الجريبات البكتيري المعتاد."},"reasoning":{"en":"Focus on the common staphylococcal pattern is distinct from hot-tub Pseudomonas disease. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يختلف النمط العنقودي الشائع عن مرض الزائفة المرتبط بحمام ساخن. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q081","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"MCQ","difficulty":"Easy","source":"PDF pp. 21-22","question":{"en":"Which morphology best identifies folliculitis?","ar":"أي شكل للآفة يحدد التهاب الجريبات بصورة أفضل؟"},"options":[{"letter":"A","en":"Small papules or pustules centered on hair shafts","ar":"حطاطات أو بثور صغيرة تتمركز حول ساق الشعرة"},{"letter":"B","en":"A large black eschar with edema","ar":"قشرة سوداء كبيرة مع وذمة"},{"letter":"C","en":"A sharply raised facial plaque","ar":"لويحة وجهية مرتفعة محددة"},{"letter":"D","en":"A diffuse nonfollicular leg plaque","ar":"لويحة ساق منتشرة غير جريبية"}],"correct":"A","explanation":{"en":"Folliculitis produces small erythematous papules or pustules centered on follicles, often with mild itch or tenderness.","ar":"يُنتج التهاب الجريبات حطاطات أو بثورًا حمامية صغيرة تتمركز حول الجريبات مع حكة أو ألم خفيف."},"reasoning":{"en":"Focus on seeing a hair emerge from the center of a pustule is highly suggestive. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على خروج شعرة من مركز البثرة علامة شديدة الدلالة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q082","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"Case","difficulty":"Medium","source":"PDF pp. 21-22","question":{"en":"A man develops pustules in the beard area after frequent close shaving. What predisposing mechanism is most likely?","ar":"رجل ظهرت لديه بثور بمنطقة اللحية بعد حلاقة متقاربة متكررة. ما الآلية المهيئة الأرجح؟"},"options":[{"letter":"A","en":"Mechanical trauma to follicles","ar":"رض ميكانيكي للجريبات"},{"letter":"B","en":"Systemic toxin-mediated epidermal cleavage","ar":"انفصال بشروي جهازي بوساطة السموم"},{"letter":"C","en":"Lymphatic obstruction only","ar":"انسداد لمفي فقط"},{"letter":"D","en":"Aerosol spore exposure","ar":"تعرض لأبواغ بالهواء"}],"correct":"A","explanation":{"en":"Shaving causes follicular microtrauma and facilitates colonization and inflammation; deep beard involvement is termed sycosis barbae.","ar":"تسبب الحلاقة رضوضًا دقيقة بالجريبات وتُسهل الاستعمار والالتهاب، وقد يُسمى الشكل العميق باللحية سعفة الحلاق البكتيرية."},"reasoning":{"en":"Focus on the temporal link to shaving points to barrier and follicular trauma. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يربط التوقيت بعد الحلاقة الحالة برض الجريب والحاجز. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q083","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"Case","difficulty":"Medium","source":"PDF pp. 21, 26","question":{"en":"Pruritic follicular pustules appear 24 hours after use of a poorly maintained hot tub. What is the most likely pathogen?","ar":"ظهرت بثور جريبية حاكة بعد 24 ساعة من استخدام حوض ساخن سيئ الصيانة. ما الممرض الأرجح؟"},"options":[{"letter":"A","en":"Pseudomonas aeruginosa","ar":"الزائفة الزنجارية"},{"letter":"B","en":"Streptococcus pyogenes","ar":"العقدية المقيحة"},{"letter":"C","en":"Bartonella henselae","ar":"بارتونيلا هينسيلا"},{"letter":"D","en":"Bacillus anthracis","ar":"العصوية الجمرية"}],"correct":"A","explanation":{"en":"Hot-tub folliculitis is caused by P. aeruginosa in inadequately disinfected warm water.","ar":"التهاب جريبات الحوض الساخن تسببه الزائفة الزنجارية في المياه الدافئة غير المعقمة جيدًا."},"reasoning":{"en":"Focus on warm-water exposure followed by follicular lesions is the classic epidemiologic clue. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على التعرض لمياه دافئة ثم آفات جريبية هو الدليل الوبائي الكلاسيكي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q084","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"MCQ","difficulty":"Medium","source":"PDF p. 26","question":{"en":"What is the usual incubation window for hot-tub folliculitis after exposure?","ar":"ما المدة المعتادة لظهور التهاب جريبات الحوض الساخن بعد التعرض؟"},"options":[{"letter":"A","en":"About 8-48 hours","ar":"نحو 8-48 ساعة"},{"letter":"B","en":"Six months","ar":"ستة أشهر"},{"letter":"C","en":"Within 2 minutes in every case","ar":"خلال دقيقتين في كل الحالات"},{"letter":"D","en":"More than 10 years","ar":"أكثر من عشر سنوات"}],"correct":"A","explanation":{"en":"The eruption commonly appears 8-48 hours after exposure to contaminated water.","ar":"يظهر الطفح غالبًا خلال 8-48 ساعة بعد التعرض للمياه الملوثة."},"reasoning":{"en":"Focus on the short post-exposure interval fits direct follicular inoculation. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يتوافق الفاصل القصير بعد التعرض مع التلقيح المباشر للجريبات. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q085","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"Treatment","difficulty":"Easy","source":"PDF p. 26","question":{"en":"How should mild hot-tub folliculitis usually be managed?","ar":"كيف يُعالج التهاب جريبات الحوض الساخن الخفيف عادةً؟"},"options":[{"letter":"A","en":"Supportive care because it is usually self-limited","ar":"رعاية داعمة لأنه غالبًا محدود ذاتيًا"},{"letter":"B","en":"Immediate prolonged IV antibiotics","ar":"مضادات وريدية طويلة فورًا"},{"letter":"C","en":"Surgical excision of all follicles","ar":"استئصال جراحي لكل الجريبات"},{"letter":"D","en":"Systemic corticosteroids alone","ar":"كورتيكوستيرويدات جهازية وحدها"}],"correct":"A","explanation":{"en":"Most mild cases resolve spontaneously within about 10 days.","ar":"تتحسن معظم الحالات الخفيفة تلقائيًا خلال نحو 10 أيام."},"reasoning":{"en":"Focus on absence of severe or extensive disease makes antibiotic risk exceed likely benefit. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على عند غياب المرض الشديد أو الواسع قد يفوق خطر المضاد فائدته. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q086","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"Treatment","difficulty":"Medium","source":"PDF p. 25","question":{"en":"What is appropriate for moderate staphylococcal folliculitis with multiple pustules but no deep abscess?","ar":"ما العلاج المناسب لالتهاب جريبات عنقودي متوسط مع بثور متعددة دون خراج عميق؟"},"options":[{"letter":"A","en":"Topical mupirocin or clindamycin","ar":"ميوبيروسين أو كليندامايسين موضعي"},{"letter":"B","en":"Meropenem plus vancomycin","ar":"ميروبينيم مع فانكوميسين"},{"letter":"C","en":"No skin cleansing","ar":"عدم تنظيف الجلد"},{"letter":"D","en":"Oral antifungal therapy","ar":"علاج فطري فموي"}],"correct":"A","explanation":{"en":"Moderate superficial disease may be treated with topical mupirocin three times daily or topical clindamycin twice daily.","ar":"يمكن علاج المرض السطحي المتوسط بميوبيروسين موضعي ثلاث مرات يوميًا أو كليندامايسين موضعي مرتين يوميًا."},"reasoning":{"en":"Focus on multiple superficial lesions justify topical antibacterial therapy without abscess drainage. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تبرر الآفات السطحية المتعددة علاجًا بكتيريًا موضعيًا دون تصريف خراج. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q087","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"Treatment","difficulty":"Medium","source":"PDF p. 25","question":{"en":"Which oral agent is appropriate for extensive staphylococcal folliculitis when MRSA is not suspected?","ar":"أي دواء فموي مناسب لالتهاب جريبات عنقودي واسع عند عدم الاشتباه في MRSA؟"},"options":[{"letter":"A","en":"Cephalexin","ar":"سيفاليكسين"},{"letter":"B","en":"Fluconazole","ar":"فلوكونازول"},{"letter":"C","en":"Rifampin monotherapy","ar":"ريفامبين وحده"},{"letter":"D","en":"Acyclovir","ar":"أسيكلوفير"}],"correct":"A","explanation":{"en":"Cephalexin is a listed oral option for extensive disease when MSSA is expected.","ar":"السيفاليكسين خيار فموي مذكور للمرض الواسع عند توقع MSSA."},"reasoning":{"en":"Focus on the severity requires systemic therapy, but the resistance profile does not require MRSA coverage. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تستلزم الشدة علاجًا جهازيًا لكن نمط المقاومة لا يتطلب تغطية MRSA. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q088","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"Treatment","difficulty":"Hard","source":"PDF p. 25","question":{"en":"Which oral regimen is appropriate for extensive folliculitis when MRSA is suspected?","ar":"أي نظام فموي مناسب لالتهاب جريبات واسع عند الاشتباه في MRSA؟"},"options":[{"letter":"A","en":"Doxycycline, TMP-SMX, or clindamycin","ar":"دوكسيسيكلين أو TMP-SMX أو كليندامايسين"},{"letter":"B","en":"Penicillin V only","ar":"بنسلين V فقط"},{"letter":"C","en":"Amoxicillin alone","ar":"أموكسيسيلين وحده"},{"letter":"D","en":"Topical emollient only","ar":"مرطب موضعي فقط"}],"correct":"A","explanation":{"en":"Doxycycline, TMP-SMX, and clindamycin are listed MRSA-active oral options for extensive or severe folliculitis.","ar":"الدوكسيسيكلين وTMP-SMX والكليندامايسين خيارات فموية فعالة ضد MRSA في التهاب الجريبات الواسع أو الشديد."},"reasoning":{"en":"Focus on suspected resistant staphylococci require an agent with MRSA activity. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يحتاج الاشتباه في عنقوديات مقاومة دواءً فعالًا ضد MRSA. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q089","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"Case","difficulty":"Hard","source":"PDF p. 26","question":{"en":"A patient on prolonged antibiotics for acne develops gram-negative folliculitis. Which organisms are plausible?","ar":"مريض يستخدم مضادات لفترة طويلة لعلاج حب الشباب وظهر لديه التهاب جريبات بسالبات الغرام. أي كائنات محتملة؟"},"options":[{"letter":"A","en":"Klebsiella, Enterobacter, or Proteus species","ar":"أنواع كليبسيلا أو إنتروبكتر أو بروتيوس"},{"letter":"B","en":"Only Streptococcus pyogenes","ar":"العقدية المقيحة فقط"},{"letter":"C","en":"Only Bacillus anthracis","ar":"العصوية الجمرية فقط"},{"letter":"D","en":"Only Bartonella henselae","ar":"بارتونيلا هينسيلا فقط"}],"correct":"A","explanation":{"en":"Long-term antibiotic exposure can select gram-negative organisms such as Klebsiella, Enterobacter, and Proteus.","ar":"قد ينتقي التعرض الطويل للمضادات كائنات سالبة الغرام مثل الكليبسيلا والإنتروبكتر والبروتيوس."},"reasoning":{"en":"Focus on antibiotic pressure shifts the follicular flora away from typical staphylococci. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يغير ضغط المضادات فلورا الجريبات بعيدًا عن العنقوديات المعتادة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q090","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"Treatment","difficulty":"Hard","source":"PDF p. 26","question":{"en":"What treatment may be considered for recalcitrant gram-negative folliculitis?","ar":"ما العلاج الذي يمكن التفكير فيه لالتهاب الجريبات بسالبات الغرام المقاوم؟"},"options":[{"letter":"A","en":"Isotretinoin for several months","ar":"إيزوتريتينوين لعدة أشهر"},{"letter":"B","en":"A single topical steroid dose","ar":"جرعة واحدة من ستيرويد موضعي"},{"letter":"C","en":"No treatment under any circumstances","ar":"عدم العلاج في كل الظروف"},{"letter":"D","en":"Immediate lymph-node excision","ar":"استئصال عقدة لمفية فوري"}],"correct":"A","explanation":{"en":"The chapter lists isotretinoin for 4-5 months in recalcitrant gram-negative folliculitis.","ar":"يذكر الفصل الإيزوتريتينوين لمدة 4-5 أشهر في الحالات المقاومة من التهاب الجريبات بسالبات الغرام."},"reasoning":{"en":"Focus on recalcitrant disease after antimicrobial approaches may require altering follicular sebum and ecology. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على قد يتطلب المرض المقاوم بعد العلاج المضاد تغيير دهون الجريب وبيئته. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q091","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"MCQ","difficulty":"Hard","source":"PDF p. 22","question":{"en":"Which is a potential long-term complication of deep folliculitis?","ar":"أي مما يلي مضاعفة طويلة المدى محتملة لالتهاب الجريبات العميق؟"},"options":[{"letter":"A","en":"Cicatricial alopecia","ar":"الثعلبة الندبية"},{"letter":"B","en":"Coral-red fluorescence","ar":"التألق الأحمر المرجاني"},{"letter":"C","en":"Post-streptococcal nephritis in every case","ar":"التهاب كلى تالٍ للعقديات في كل حالة"},{"letter":"D","en":"Black eschar without pain","ar":"قشرة سوداء غير مؤلمة"}],"correct":"A","explanation":{"en":"Deep follicular destruction can cause permanent scarring and irreversible hair loss as cicatricial alopecia.","ar":"قد يؤدي تدمير الجريب العميق إلى تندب دائم وفقد شعر غير عكوس على هيئة ثعلبة ندبية."},"reasoning":{"en":"Focus on damage to the entire follicle can destroy the regenerative structure. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على قد تدمر إصابة الجريب كاملًا البنية المسؤولة عن التجدد. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q092","topic":"folliculitis","topicEn":"Bacterial Folliculitis","topicAr":"التهاب جريبات الشعر البكتيري","type":"Image","difficulty":"Easy","source":"PDF p. 21","question":{"en":"The image shows multiple small pustules centered on hair follicles. What is the diagnosis?","ar":"تُظهر الصورة بثورًا صغيرة متعددة تتمركز حول جريبات الشعر. ما التشخيص؟"},"options":[{"letter":"A","en":"Bacterial folliculitis","ar":"التهاب الجريبات البكتيري"},{"letter":"B","en":"Erysipelas","ar":"الحمرة"},{"letter":"C","en":"Ecthyma","ar":"الإكثيما"},{"letter":"D","en":"Cutaneous anthrax","ar":"الجمرة الخبيثة الجلدية"}],"correct":"A","explanation":{"en":"Follicle-centered pustules are the hallmark of bacterial folliculitis.","ar":"البثور المتمركزة حول الجريبات هي العلامة المميزة لالتهاب الجريبات البكتيري."},"reasoning":{"en":"Focus on the central hair shaft differentiates it from nonfollicular pustular disease. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على تميز الشعرة المركزية الحالة عن الأمراض البثرية غير الجريبية. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"},{"id":"Q093","topic":"furuncle","topicEn":"Furuncle","topicAr":"الدُّمَّل","type":"MCQ","difficulty":"Easy","source":"PDF p. 23","question":{"en":"What is a furuncle?","ar":"ما الدمل؟"},"options":[{"letter":"A","en":"A deep infection of a hair follicle extending into surrounding dermis","ar":"عدوى عميقة لجريب شعري تمتد إلى الأدمة المحيطة"},{"letter":"B","en":"A superficial flexural patch","ar":"لطخة سطحية في الثنيات"},{"letter":"C","en":"A toxin-mediated generalized peeling disorder","ar":"اضطراب تقشر عام بوساطة السموم"},{"letter":"D","en":"A lymph-node infection after a cat scratch","ar":"عدوى عقدة لمفية بعد خدش قطة"}],"correct":"A","explanation":{"en":"A furuncle is a localized necrotizing infection of a follicle and adjacent dermis or subcutaneous tissue.","ar":"الدمل عدوى نخرية موضعية لجريب الشعر والأدمة أو النسيج تحت الجلد المجاور."},"reasoning":{"en":"Focus on it represents progression beyond superficial folliculitis. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يمثل تطورًا يتجاوز التهاب الجريبات السطحي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q094","topic":"furuncle","topicEn":"Furuncle","topicAr":"الدُّمَّل","type":"MCQ","difficulty":"Easy","source":"PDF p. 23","question":{"en":"Which pathogen most commonly causes a furuncle?","ar":"ما الممرض الأكثر شيوعًا في الدمل؟"},"options":[{"letter":"A","en":"Staphylococcus aureus","ar":"المكورات العنقودية الذهبية"},{"letter":"B","en":"Corynebacterium minutissimum","ar":"الوتدية الدقيقة"},{"letter":"C","en":"Bartonella henselae","ar":"بارتونيلا هينسيلا"},{"letter":"D","en":"Bacillus anthracis","ar":"العصوية الجمرية"}],"correct":"A","explanation":{"en":"Most furuncles are caused by S. aureus.","ar":"تسبب المكورات العنقودية الذهبية معظم الدمامل."},"reasoning":{"en":"Focus on the same organism commonly causes folliculitis and can extend deeper to form a boil. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يسبب الميكروب نفسه التهاب الجريبات وقد يمتد أعمق ليكوّن دملًا. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q095","topic":"furuncle","topicEn":"Furuncle","topicAr":"الدُّمَّل","type":"Case","difficulty":"Medium","source":"PDF p. 23","question":{"en":"A tender firm nodule becomes fluctuant and later drains a necrotic core. What is the most likely diagnosis?","ar":"تحولت عقدة مؤلمة صلبة إلى متموجة ثم صرفت مركزًا نخريًا. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Furuncle","ar":"دمل"},{"letter":"B","en":"Erythrasma","ar":"إريثرازما"},{"letter":"C","en":"Non-bullous impetigo","ar":"قوباء غير فقاعية"},{"letter":"D","en":"Erysipelas","ar":"حمرة"}],"correct":"A","explanation":{"en":"A furuncle begins as a tender nodule, accumulates pus, develops a necrotic center, and may drain spontaneously.","ar":"يبدأ الدمل كعقدة مؤلمة ثم يتجمع القيح ويتكون مركز نخري وقد يُصرف تلقائيًا."},"reasoning":{"en":"Focus on fluctuation and a necrotic core indicate a localized follicular abscess. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يشير التموج والمركز النخري إلى خراج جريبي موضعي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q096","topic":"furuncle","topicEn":"Furuncle","topicAr":"الدُّمَّل","type":"MCQ","difficulty":"Medium","source":"PDF p. 23","question":{"en":"Which sites commonly develop furuncles because of friction, pressure, or moisture?","ar":"ما المواضع التي تظهر فيها الدمامل شائعًا بسبب الاحتكاك أو الضغط أو الرطوبة؟"},"options":[{"letter":"A","en":"Neck, axillae, buttocks, thighs, and anogenital region","ar":"الرقبة والإبط والأليتان والفخذان والمنطقة الشرجية التناسلية"},{"letter":"B","en":"Only the cornea","ar":"القرنية فقط"},{"letter":"C","en":"Only the tongue","ar":"اللسان فقط"},{"letter":"D","en":"Only the nails","ar":"الأظافر فقط"}],"correct":"A","explanation":{"en":"Furuncles favor frictional and moist areas including the face, neck, axillae, buttocks, thighs, and anogenital region.","ar":"تفضل الدمامل المناطق الرطبة والمعرضة للاحتكاك مثل الوجه والرقبة والإبط والأليتين والفخذين والمنطقة الشرجية التناسلية."},"reasoning":{"en":"Focus on local trauma and occlusion promote follicular invasion. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يساعد الرض والانسداد الموضعيان على غزو الجريب. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q097","topic":"furuncle","topicEn":"Furuncle","topicAr":"الدُّمَّل","type":"Treatment","difficulty":"Easy","source":"PDF p. 23","question":{"en":"What is the mainstay of treatment for a fluctuant furuncle?","ar":"ما أساس علاج الدمل المتموج؟"},"options":[{"letter":"A","en":"Incision and drainage","ar":"الشق والتصريف"},{"letter":"B","en":"Topical moisturizer alone","ar":"مرطب موضعي فقط"},{"letter":"C","en":"Long-term antifungal therapy","ar":"علاج فطري طويل"},{"letter":"D","en":"No intervention even with abscess formation","ar":"عدم التدخل حتى مع تكون خراج"}],"correct":"A","explanation":{"en":"Drainage removes the purulent collection and is the primary treatment for a mature fluctuant boil.","ar":"يزيل التصريف التجمع القيحي وهو العلاج الأساسي للدمل الناضج المتموج."},"reasoning":{"en":"Focus on source control is more important than antibiotics alone in a drainable abscess. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على السيطرة على المصدر أهم من المضادات وحدها في الخراج القابل للتصريف. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q098","topic":"furuncle","topicEn":"Furuncle","topicAr":"الدُّمَّل","type":"Treatment","difficulty":"Hard","source":"PDF p. 23","question":{"en":"When should systemic antibiotics be added to incision and drainage of a furuncle?","ar":"متى تُضاف المضادات الجهازية إلى شق وتصريف الدمل؟"},"options":[{"letter":"A","en":"With extensive disease, systemic symptoms, high-risk host factors, or surrounding cellulitis","ar":"مع المرض الواسع أو الأعراض الجهازية أو عوامل خطورة المضيف أو التهاب خلوي محيط"},{"letter":"B","en":"For every tiny asymptomatic follicular papule","ar":"لكل حطاطة جريبية صغيرة بلا أعراض"},{"letter":"C","en":"Only after complete healing","ar":"فقط بعد الالتئام الكامل"},{"letter":"D","en":"Never under any circumstance","ar":"لا تُستخدم مطلقًا"}],"correct":"A","explanation":{"en":"Antibiotics are reserved for more extensive infection, systemic illness, surrounding cellulitis, recurrent disease, or vulnerable patients.","ar":"تُحجز المضادات للعدوى الأوسع أو المرض الجهازي أو الالتهاب الخلوي المحيط أو التكرار أو المرضى الأكثر عرضة للخطر."},"reasoning":{"en":"Focus on drainage is sufficient for many simple lesions, while severity and host risk justify systemic therapy. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يكفي التصريف لكثير من الآفات البسيطة، بينما تبرر الشدة وخطورة المضيف العلاج الجهازي. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q099","topic":"furuncle","topicEn":"Furuncle","topicAr":"الدُّمَّل","type":"Case","difficulty":"Hard","source":"PDF p. 23","question":{"en":"A patient has repeated furuncles despite adequate drainage. Which hidden reservoir should be considered?","ar":"مريض يعاني دمامل متكررة رغم التصريف المناسب. أي مستودع خفي ينبغي التفكير فيه؟"},"options":[{"letter":"A","en":"Chronic nasal colonization with S. aureus","ar":"استعمار أنفي مزمن بالمكورات العنقودية الذهبية"},{"letter":"B","en":"Chronic ocular Bartonella infection","ar":"عدوى عينية مزمنة ببارتونيلا"},{"letter":"C","en":"Intestinal Bacillus anthracis carriage","ar":"حمل معوي للعصوية الجمرية"},{"letter":"D","en":"Fungal infection of all lymph nodes","ar":"عدوى فطرية بكل العقد اللمفية"}],"correct":"A","explanation":{"en":"Recurrent boils may reflect persistent S. aureus colonization, particularly in the anterior nares.","ar":"قد تعكس الدمامل المتكررة استعمارًا مستمرًا بالمكورات العنقودية الذهبية، خصوصًا في فتحتي الأنف."},"reasoning":{"en":"Focus on recurrence after adequate source control suggests ongoing recolonization. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يشير التكرار بعد السيطرة المناسبة على المصدر إلى إعادة استعمار مستمرة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":null},{"id":"Q100","topic":"furuncle","topicEn":"Furuncle","topicAr":"الدُّمَّل","type":"Image","difficulty":"Medium","source":"PDF p. 23","question":{"en":"The image shows a solitary tender erythematous nodule with a central pustular point. What is the diagnosis?","ar":"تُظهر الصورة عقدة حمامية مؤلمة منفردة ذات نقطة بثرية مركزية. ما التشخيص؟"},"options":[{"letter":"A","en":"Furuncle","ar":"دمل"},{"letter":"B","en":"Carbuncle","ar":"جمرة"},{"letter":"C","en":"Erythrasma","ar":"إريثرازما"},{"letter":"D","en":"Erysipelas","ar":"حمرة"}],"correct":"A","explanation":{"en":"A solitary deep follicular nodule with a central purulent focus is typical of a furuncle.","ar":"العقدة الجريبية العميقة المنفردة ذات البؤرة القيحية المركزية نموذجية للدمل."},"reasoning":{"en":"Focus on a single boil lacks the multiple connected drainage points of a carbuncle. This clue supports option A and makes the alternatives less consistent with the chapter’s clinical pattern.","ar":"ركّز على يفتقر الدمل المنفرد إلى نقاط التصريف المتعددة المتصلة الموجودة في الجمرة. تدعم هذه العلامة الخيار A وتجعل البدائل أقل توافقًا مع النمط السريري المذكور في الفصل."},"image":"data:image/webp;base64,"}]);
